265→+function writePlayerMail(
266→+  w: PacketWriter,
267→+  opts: {
268→+    messageId: number;
269→+    senderGuid: bigint;
270→+    subject: string;
271→+    body: string;
272→+    flags?: number;
273→+    expirationTime?: number;
274→+    money?: number;
275→+    itemCount?: number;
276→+  },
277→+) {
278→+  const sizePos = w.offset;
279→+  w.uint16LE(0);
280→+  const startPos = w.offset;
281→+  w.uint32LE(opts.messageId);
282→+  w.uint8(MailMessageType.NORMAL);
283→+  w.uint64LE(opts.senderGuid);
284→+  w.uint32LE(0);
285→+  w.uint32LE(0);
286→+  w.uint32LE(41);
287→+  w.uint32LE(opts.money ?? 0);
288→+  w.uint32LE(opts.flags ?? MailCheckMask.HAS_BODY);
289→+  w.floatLE(opts.expirationTime ?? 1.0);
290→+  w.uint32LE(0);
291→+  w.cString(opts.subject);
292→+  w.cString(opts.body);
293→+  w.uint8(opts.itemCount ?? 0);
294→+  const endPos = w.offset;
295→+  const buf = w.finish();
296→+  const view = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
297→+  view.setUint16(sizePos, endPos - startPos, true);
298→+  return new Uint8Array(buf);
299→+}
