592→+// src/wow/protocol/mail.ts
593→+import { PacketReader, PacketWriter } from "wow/protocol/packet";
594→+
595→+export const MailMessageType = {
596→+  NORMAL: 0,
597→+  AUCTION: 2,
598→+  CREATURE: 3,
599→+  GAMEOBJECT: 4,
600→+  CALENDAR: 5,
601→+} as const;
602→+
603→+export const MailCheckMask = {
604→+  NONE: 0x00,
605→+  READ: 0x01,
606→+  RETURNED: 0x02,
607→+  COPIED: 0x04,
608→+  COD_PAYMENT: 0x08,
609→+  HAS_BODY: 0x10,
610→+} as const;
611→+
612→+export const MailAction = {
613→+  SEND: 0,
614→+  MONEY_TAKEN: 1,
615→+  ITEM_TAKEN: 2,
616→+  RETURNED_TO_SENDER: 3,
617→+  DELETED: 4,
618→+  MADE_PERMANENT: 5,
619→+} as const;
620→+
621→+export const MailResult = {
622→+  OK: 0,
623→+  ERR_EQUIP_ERROR: 1,
624→+  ERR_CANNOT_SEND_TO_SELF: 2,
625→+  ERR_NOT_ENOUGH_MONEY: 3,
626→+  ERR_RECIPIENT_NOT_FOUND: 4,
627→+  ERR_NOT_YOUR_TEAM: 5,
628→+  ERR_INTERNAL_ERROR: 6,
629→+  ERR_DISABLED_FOR_TRIAL_ACC: 14,
630→+  ERR_RECIPIENT_CAP_REACHED: 15,
631→+  ERR_CANT_SEND_WRAPPED_COD: 16,
632→+  ERR_MAIL_AND_CHAT_SUSPENDED: 17,
633→+  ERR_TOO_MANY_ATTACHMENTS: 18,
634→+  ERR_MAIL_ATTACHMENT_INVALID: 19,
635→+  ERR_ITEM_HAS_EXPIRED: 21,
636→+} as const;
637→+
638→+export type MailEntry = {
639→+  messageId: number;
640→+  messageType: number;
641→+  senderGuid?: bigint;
642→+  senderEntry?: number;
643→+  cod: number;
644→+  stationery: number;
645→+  money: number;
646→+  flags: number;
647→+  expirationDays: number;
648→+  subject: string;
649→+  body: string;
650→+  itemCount: number;
651→+};
652→+
653→+export type MailListResult = {
654→+  totalCount: number;
655→+  entries: MailEntry[];
656→+};
657→+
658→+export type SendMailResultPacket = {
659→+  mailId: number;
660→+  action: number;
661→+  result: number;
662→+};
663→+
664→+export function parseShowMailbox(r: PacketReader): bigint {
665→+  return r.uint64LE();
666→+}
667→+
668→+export function parseMailListResult(r: PacketReader): MailListResult {
669→+  const totalCount = r.uint32LE();
670→+  const count = r.uint8();
671→+  const entries: MailEntry[] = [];
672→+  for (let i = 0; i < count; i++) {
673→+    const size = r.uint16LE();
674→+    const entryStart = r.offset;
675→+    const messageId = r.uint32LE();
676→+    const messageType = r.uint8();
677→+    let senderGuid: bigint | undefined;
678→+    let senderEntry: number | undefined;
679→+    if (messageType === MailMessageType.NORMAL) {
680→+      senderGuid = r.uint64LE();
681→+    } else {
682→+      senderEntry = r.uint32LE();
683→+    }
684→+    const cod = r.uint32LE();
685→+    r.uint32LE();
686→+    const stationery = r.uint32LE();
687→+    const money = r.uint32LE();
688→+    const flags = r.uint32LE();
689→+    const expirationDays = r.floatLE();
690→+    r.uint32LE();
691→+    const subject = r.cString();
692→+    const body = r.cString();
693→+    const itemCount = r.uint8();
694→+    const consumed = r.offset - entryStart;
695→+    if (consumed < size) r.skip(size - consumed);
696→+    entries.push({
697→+      messageId,
698→+      messageType,
699→+      senderGuid,
700→+      senderEntry,
701→+      cod,
702→+      stationery,
703→+      money,
704→+      flags,
705→+      expirationDays,
706→+      subject,
707→+      body,
708→+      itemCount,
709→+    });
710→+  }
711→+  return { totalCount, entries };
712→+}
713→+
714→+export function parseSendMailResult(r: PacketReader): SendMailResultPacket {
715→+  return {
716→+    mailId: r.uint32LE(),
717→+    action: r.uint32LE(),
718→+    result: r.uint32LE(),
719→+  };
720→+}
721→+
722→+export function buildGetMailList(mailboxGuid: bigint): Uint8Array {
723→+  const w = new PacketWriter();
724→+  w.uint64LE(mailboxGuid);
725→+  return w.finish();
726→+}
727→+
728→+export function buildSendMail(
729→+  mailboxGuid: bigint,
730→+  receiver: string,
731→+  subject: string,
732→+  body: string,
733→+): Uint8Array {
734→+  const w = new PacketWriter();
735→+  w.uint64LE(mailboxGuid);
736→+  w.cString(receiver);
737→+  w.cString(subject);
738→+  w.cString(body);
739→+  w.uint32LE(0);
740→+  w.uint32LE(0);
741→+  w.uint8(0);
742→+  w.uint32LE(0);
743→+  w.uint32LE(0);
744→+  w.uint32LE(0);
745→+  w.uint32LE(0);
746→+  return w.finish();
747→+}
748→+
749→+export function buildMailDelete(
750→+  mailboxGuid: bigint,
751→+  mailId: number,
752→+): Uint8Array {
753→+  const w = new PacketWriter();
754→+  w.uint64LE(mailboxGuid);
755→+  w.uint32LE(mailId);
756→+  w.uint32LE(0);
757→+  return w.finish();
758→+}
759→+
760→+export function buildMailMarkAsRead(
761→+  mailboxGuid: bigint,
762→+  mailId: number,
763→+): Uint8Array {
764→+  const w = new PacketWriter();
765→+  w.uint64LE(mailboxGuid);
766→+  w.uint32LE(mailId);
767→+  return w.finish();
768→+}
769→+
770→+export function formatMailResultError(result: number): string | undefined {
771→+  switch (result) {
772→+    case MailResult.OK:
773→+      return undefined;
774→+    case MailResult.ERR_CANNOT_SEND_TO_SELF:
775→+      return "Cannot send mail to yourself.";
776→+    case MailResult.ERR_NOT_ENOUGH_MONEY:
777→+      return "Not enough gold to send mail.";
778→+    case MailResult.ERR_RECIPIENT_NOT_FOUND:
779→+      return "Player not found.";
780→+    case MailResult.ERR_NOT_YOUR_TEAM:
781→+      return "Cannot send mail to the opposite faction.";
782→+    case MailResult.ERR_INTERNAL_ERROR:
783→+      return "Internal mail error.";
784→+    case MailResult.ERR_DISABLED_FOR_TRIAL_ACC:
785→+      return "Trial accounts cannot send mail.";
786→+    case MailResult.ERR_RECIPIENT_CAP_REACHED:
787→+      return "Recipient's mailbox is full.";
788→+    case MailResult.ERR_MAIL_AND_CHAT_SUSPENDED:
789→+      return "Mail is suspended on this account.";
790→+    case MailResult.ERR_TOO_MANY_ATTACHMENTS:
791→+      return "Too many attachments.";
792→+    default:
793→+      return `Mail error (code ${result}).`;
794→+  }
795→+}
796→+```
